import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { fetchGroups } from '../services/api';
import groupImage from '../assets/photogroup1.jpg';

export default function Groups() {
    const [groups, setGroups] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        fetchGroups().then(data => setGroups(data));
    }, []);

    return (
        <div className="p-6 min-h-screen bg-gray-100">
            <h1 className="text-3xl font-bold mb-6 text-center text-gray-800">Mes Groupes</h1>

            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
                {groups.map(group => (
                    <div
                        key={group.id}
                        onClick={() => navigate(`/groups/${group.id}`)}
                        className="bg-white rounded-xl shadow-lg overflow-hidden cursor-pointer transition-transform transform hover:scale-105"
                    >
                        <img src={groupImage} alt={group.name} className="w-full h-40 object-cover" />

                        <div className="p-4">
                            <h2 className="text-lg font-semibold text-gray-900">{group.name}</h2>
                            <p className="text-gray-600">{group.members.length} membres</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}
